```python
def is_bored(S):
    if not S:
        return 0

    # Split the string into sentences using '.', '?', and '!' as delimiters
    # We'll split on these punctuation marks but keep track of sentence boundaries
    sentences = []
    current_sentence = ""

    for char in S:
        if char in '.!?':
            # Add the current sentence (stripped of whitespace) to our list
            if current_sentence.strip():
                sentences.append(current_sentence.strip())
            current_sentence = ""
        else:
            current_sentence += char

    # Don't forget the last sentence if the string doesn't end with punctuation
    if current_sentence.strip():
        sentences.append(current_sentence.strip())

    # Count sentences that start with "I " or are exactly "I"
    boredom_count = 0
    for sentence in sentences:
        # Strip leading/trailing whitespace and check if it starts with "I "
        # or is exactly "I" (though "I" alone would be unusual in context)
        stripped = sentence.strip()
        if stripped.startswith("I ") or stripped == "I":
            boredom_count += 1

    return boredom_count
```

```python
def fib(n: int) -> int:
    if n <= 0:
        return 0
    elif n == 1:
        return 1

    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b
```

```python
def even_odd_count(num):
    # Convert to string and remove negative sign if present
    num_str = str(abs(num))

    even_count = 0
    odd_count = 0

    # Count even and odd digits
    for digit_char in num_str:
        digit = int(digit_char)
        if digit % 2 == 0:
            even_count += 1
        else:
            odd_count += 1

    return (even_count, odd_count)
```

```python
from typing import List

def below_zero(operations: List[int]) -> bool:
    balance = 0
    for operation in operations:
        balance += operation
        if balance < 0:
            return True
    return False
```

